def reverse_list(head):
    prev = None
    current = head
    while current:
        next_node = current.next
        current.next = prev
        prev = current
        current = next_node
    return prev

def print_list(head):
    curr = head
    while curr:
        print(f"{curr.value} -> ", end="")
        curr = curr.next
    print("None")

import asyncio
import aiohttp

async def fetch_all(urls):
    async with aiohttp.ClientSession() as session:
        tasks = []
        for url in urls:
            tasks.append(fetch_one(session, url))
        return await asyncio.gather(*tasks)

async def fetch_one(session, url):
    try:
        async with session.get(url, timeout=10) as response:
            return await response.json()
    except Exception as e:
        return {"error": str(e), "url": url}

class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            print(f"Added {amount} to the balance")
        return self.balance

    def withdraw(self, amount):
        if 0 < amount <= self.balance:
            self.balance -= amount
            print(f"Withdrew {amount}")
        else:
            print("Insufficient funds!")
        return self.balance

def process_temperatures(celsius_data):
    # Convert a list of Celsius temperatures to Fahrenheit using dictionary comprehension
    fahrenheit_dict = {f"Day_{i+1}": (temp * 9/5) + 32 for i, temp in enumerate(celsius_data)}

    hottest_day = max(fahrenheit_dict, key=fahrenheit_dict.get)
    average_temp = sum(fahrenheit_dict.values()) / len(fahrenheit_dict)

    return {
        "data": fahrenheit_dict,
        "hottest": hottest_day,
        "average": round(average_temp, 2)
    }

import time
from functools import wraps

def retry_with_backoff(retries=3, backoff_in_seconds=1):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            x = 0
            while True:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if x == retries:
                        raise e
                    sleep = (backoff_in_seconds * 2 ** x)
                    time.sleep(sleep)
                    x += 1
        return wrapper
    return decorator
